function useTypewriter(words, speed=75, pause=2000) {
  const [text,setText]=useState(""); const [wi,setWi]=useState(0);
  const [ci,setCi]=useState(0); const [del,setDel]=useState(false);
  useEffect(()=>{
    const w=words[wi]; let t;
    if(!del&&ci<=w.length)     t=setTimeout(()=>setCi(c=>c+1),speed);
    else if(!del&&ci>w.length) t=setTimeout(()=>setDel(true),pause);
    else if(del&&ci>0)         t=setTimeout(()=>setCi(c=>c-1),speed/2);
    else{setDel(false);setWi(i=>(i+1)%words.length);}
    setText(w.slice(0,ci)); return()=>clearTimeout(t);
  },[ci,del,wi]);
  return text;
}

function AnimBar({level,color,delay=0}){
  const [w,setW]=useState(0);
  useEffect(()=>{const t=setTimeout(()=>setW(level),300+delay);return()=>clearTimeout(t);},[]);
  return(
    <div style={{height:6,background:"rgba(255,255,255,0.06)",borderRadius:10,overflow:"hidden"}}>
      <div style={{height:"100%",width:`${w}%`,background:`linear-gradient(90deg,${color}88,${color})`,borderRadius:10,transition:"width 1.2s cubic-bezier(.4,0,.2,1)",boxShadow:`0 0 12px ${color}55`}}/>
    </div>
  );
}

