/* ── IMAGE GALLERY ── */
function Gallery({ images, color, glow }) {
  const [active, setActive] = useState(0);
  const [zoomed, setZoomed] = useState(false);
  const imgs = images;

  useEffect(() => { setActive(0); }, [images]);

  return (
    <div style={{flex:1,minWidth:0}}>
      {/* Main image */}
      <div
        onClick={() => setZoomed(true)}
        style={{
          position:"relative", borderRadius:12, overflow:"hidden",
          border:`2px solid ${color}44`, cursor:"zoom-in",
          boxShadow:`0 0 40px ${glow}33`,
          background:"#0a0f1a",
          aspectRatio:"16/9",
        }}>
        <img
          src={IMG[imgs[active].src]}
          alt={imgs[active].label}
          style={{width:"100%",height:"100%",objectFit:"cover",display:"block",transition:"transform 0.4s"}}
        />
        <div style={{position:"absolute",bottom:0,left:0,right:0,
          background:"linear-gradient(transparent,rgba(0,0,0,0.7))",
          padding:"20px 14px 10px",display:"flex",justifyContent:"space-between",alignItems:"flex-end"}}>
          <span style={{fontSize:11,color:"rgba(255,255,255,0.7)",fontFamily:"monospace"}}>{imgs[active].label}</span>
          <span style={{fontSize:10,color:color,fontFamily:"monospace",opacity:0.8}}>🔍 Click to zoom</span>
        </div>
        {/* glow border pulse */}
        <div style={{position:"absolute",inset:0,borderRadius:10,border:`1px solid ${color}22`,pointerEvents:"none"}}/>
      </div>

      {/* Thumbnail strip — only if multiple */}
      {imgs.length > 1 && (
        <div style={{display:"flex",gap:8,marginTop:10,overflowX:"auto",paddingBottom:4}}>
          {imgs.map((img,i)=>(
            <div key={i} onClick={()=>setActive(i)}
              style={{flexShrink:0,width:90,height:56,borderRadius:6,overflow:"hidden",cursor:"pointer",
                border:`2px solid ${i===active?color:"rgba(255,255,255,0.08)"}`,
                opacity:i===active?1:0.5,transition:"all 0.2s",
                boxShadow:i===active?`0 0 12px ${glow}`:undefined}}>
              <img src={IMG[img.src]} alt={img.label} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
            </div>
          ))}
        </div>
      )}

      {/* Zoom modal */}
      {zoomed && (
        <div onClick={()=>setZoomed(false)}
          style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.92)",zIndex:1000,
            display:"flex",alignItems:"center",justifyContent:"center",cursor:"zoom-out",padding:20}}>
          <div style={{position:"relative",maxWidth:"95vw",maxHeight:"92vh"}}>
            <img src={IMG[imgs[active].src]} alt="" style={{maxWidth:"100%",maxHeight:"88vh",objectFit:"contain",borderRadius:8,boxShadow:`0 0 60px ${glow}`}}/>
            <div style={{position:"absolute",top:-36,right:0,color:"rgba(255,255,255,0.5)",fontSize:13,fontFamily:"monospace"}}>ESC or click to close</div>
            {imgs.length>1&&(
              <div style={{position:"absolute",bottom:-40,left:"50%",transform:"translateX(-50%)",display:"flex",gap:8}}>
                {imgs.map((_,i)=>(
                  <button key={i} onClick={e=>{e.stopPropagation();setActive(i);}}
                    style={{width:i===active?20:8,height:8,borderRadius:4,background:i===active?color:"rgba(255,255,255,0.2)",border:"none",cursor:"pointer",transition:"all 0.2s"}}/>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

