const CSS=`
  @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Outfit:wght@300;400;500;600;700;800&display=swap');
  *{box-sizing:border-box;margin:0;padding:0;}
  html{scroll-behavior:smooth;}
  ::-webkit-scrollbar{width:4px;height:4px;}
  ::-webkit-scrollbar-thumb{background:#1e293b;border-radius:4px;}
  @keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
  @keyframes pulseG{0%,100%{box-shadow:0 0 0 0 rgba(16,185,129,0.5)}50%{box-shadow:0 0 0 8px rgba(16,185,129,0)}}
  @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
  .fade-up{animation:fadeUp 0.7s ease forwards;opacity:0;}
  .a0{animation-delay:0s}.a1{animation-delay:.12s}.a2{animation-delay:.22s}.a3{animation-delay:.32s}.a4{animation-delay:.44s}.a5{animation-delay:.56s}
  .blink{color:#38bdf8;animation:blink 1s step-end infinite;}
  .mesh{position:fixed;inset:0;background:radial-gradient(ellipse 80% 60% at 20% 10%,rgba(56,189,248,0.07) 0%,transparent 60%),radial-gradient(ellipse 60% 50% at 80% 80%,rgba(168,85,247,0.07) 0%,transparent 60%);pointer-events:none;z-index:0;}
  .grid-bg{position:fixed;inset:0;background-image:linear-gradient(rgba(255,255,255,0.02) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,0.02) 1px,transparent 1px);background-size:64px 64px;pointer-events:none;z-index:0;}
  .stat-card{background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:12px;padding:18px 14px;text-align:center;display:flex;flex-direction:column;align-items:center;gap:5px;transition:all 0.3s;cursor:default;}
  .stat-card:hover{transform:translateY(-4px);border-color:rgba(56,189,248,0.35);background:rgba(56,189,248,0.04);}
  .btn-primary{transition:all 0.2s;}.btn-primary:hover{box-shadow:0 6px 32px rgba(56,189,248,0.5)!important;transform:translateY(-1px);}
  .btn-secondary{transition:all 0.2s;}.btn-secondary:hover{border-color:rgba(255,255,255,0.25)!important;color:#e2e8f0!important;}
  .chip{font-size:12px;color:#94a3b8;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);border-radius:6px;padding:4px 11px;font-family:monospace;transition:all 0.15s;cursor:default;}
  .chip:hover{background:rgba(56,189,248,0.12);border-color:#38bdf8;color:#38bdf8;transform:translateY(-1px);}
  .nav-btn:hover{color:#e2e8f0!important;}
  .proj-tab:hover{transform:translateY(-1px);}
  .proj-detail{animation:fadeUp 0.4s ease forwards;}
  .skill-card:hover{background:rgba(255,255,255,0.04)!important;transform:translateY(-2px);}
  .c-card:hover{background:rgba(255,255,255,0.06)!important;border-color:rgba(255,255,255,0.15)!important;transform:translateY(-2px);}
  .socBtn:hover{background:rgba(56,189,248,0.08)!important;border-color:rgba(56,189,248,0.3)!important;color:#38bdf8!important;}
  @media(max-width:700px){
    .navLinks,.ctaNav{display:none!important;}
    .menuBtn{display:block!important;}
    .statsGrid{grid-template-columns:repeat(2,1fr)!important;}
    .aboutGrid{grid-template-columns:1fr!important;}
    .projDetailInner{flex-direction:column!important;}
  }
`;
